function parseMaybeJson(value, fallback = {}) {
  if (value && typeof value === "object") return value;
  if (typeof value !== "string") return fallback;
  try { return JSON.parse(value); } catch { return fallback; }
}

const payload = parseMaybeJson($json.payload, {});
return [{
  ...payload,
  notes: [
    ...(payload.notes || []),
    "subworkflowoffer_available_slotsinput_normalized"
  ]
}];

const ctx = $json.execution_context || {};
const stateUpdate = ctx.state_update || {};

function getAvailabilityConfig(window) {
  switch (window) {
    case "this_week":
      return {
        days_ahead: 7,
        start_offset_days: 0,
        availability_label: "los prÃ³ximos dÃ­as",
        max_slots: 3
      };

    case "next_week":
      return {
        days_ahead: 7,
        start_offset_days: 7,
        availability_label: "la prÃ³xima semana",
        max_slots: 5
      };

    case "next_14_days":
      return {
        days_ahead: 14,
        start_offset_days: 0,
        availability_label: "las prÃ³ximas dos semanas",
        max_slots: 6
      };

    case "next_30_days":
      return {
        days_ahead: 30,
        start_offset_days: 0,
        availability_label: "las prÃ³ximas semanas",
        max_slots: 8
      };

    default:
      return {
        days_ahead: 7,
        start_offset_days: 0,
        availability_label: "los prÃ³ximos dÃ­as",
        max_slots: 3
      };
  }
}

const bookingDate = ctx.booking_date || stateUpdate.booking_date || null;
const bookingTime = ctx.booking_time || stateUpdate.booking_time || null;
const slotId = ctx.slot_id || stateUpdate.slot_id || (
  bookingDate && bookingTime ? `${bookingDate}_${bookingTime}` : null
);

const isSpecificSlotCheck =
  ctx.next_goal === "check_specific_slot_availability" ||
  stateUpdate.next_goal === "check_specific_slot_availability" ||
  (
    !!bookingDate &&
    !!bookingTime &&
    ctx.availability_confirmed !== true &&
    stateUpdate.availability_confirmed !== true
  );

const config = getAvailabilityConfig(ctx.availability_window || stateUpdate.availability_window || "this_week");

return [{
  ...$json,
  db_operations: ["messages", "lead_state"],

  availability_request: {
    lead_id: ctx.lead_id,
    service_interest: ctx.service_interest,
    vehicle_type: ctx.vehicle_type,
    district: ctx.district,
    duration_minutes: ctx.duration_minutes || 120,
    calendar_id: ctx.calendar_id || "primary",

    check_type: isSpecificSlotCheck ? "specific_slot" : "list_slots",

    booking_date: bookingDate,
    booking_time: bookingTime,
    slot_id: slotId,

    availability_window: ctx.availability_window || stateUpdate.availability_window || "this_week",
    availability_label: ctx.availability_label || stateUpdate.availability_label || config.availability_label,

    days_ahead: Number(ctx.days_ahead || stateUpdate.days_ahead || config.days_ahead),
    start_offset_days: Number(ctx.start_offset_days || stateUpdate.start_offset_days || config.start_offset_days),
    max_slots: Number(ctx.max_slots || stateUpdate.max_slots || config.max_slots)
  },

  state_update: {
    ...(ctx.state_update || {}),

    stage: "booking_selection",
    intent_last: isSpecificSlotCheck ? "manual_slot_requested" : "availability_requested",
    next_goal: isSpecificSlotCheck ? "check_specific_slot_availability" : "show_available_slots",
    last_bot_action: "offer_available_slots_in_progress",

    booking_date: bookingDate,
    booking_time: bookingTime,
    slot_id: slotId,
    availability_confirmed: false,

    availability_window: ctx.availability_window || stateUpdate.availability_window || "this_week",
    availability_label: ctx.availability_label || stateUpdate.availability_label || config.availability_label,

    missing_fields: []
  }
}];

const ctx = $json.execution_context || {};

const slots =
  Array.isArray($json.slots) ? $json.slots :
  Array.isArray($json.available_slots) ? $json.available_slots :
  Array.isArray($json.booking_options) ? $json.booking_options :
  [];

function serviceLabel(service) {
  const map = {
    lavado_basico: "lavado básico",
    lavado_premium: "lavado premium",
    encerado_full: "encerado full",

    lavado_profundo: "lavado premium",
    lavado_esencial: "lavado básico",
  };

  return map[service] || "el servicio";
}

function formatSlot(slot) {
  const rawStart =
    slot.slot_start_at ||
    slot.start_at ||
    slot.start ||
    slot.datetime ||
    null;

  if (!rawStart) {
    return slot.label || "horario disponible";
  }

  const start = new Date(rawStart);

  const fecha = start.toLocaleDateString("es-CL", {
    timeZone: "America/Santiago",
    weekday: "long",
    day: "2-digit",
    month: "long"
  });

  const hora = start.toLocaleTimeString("es-CL", {
    timeZone: "America/Santiago",
    hour: "2-digit",
    minute: "2-digit"
  });

  return `${fecha} a las ${hora}`;
}

const availabilityLabel =
  $json.availability_label ||
  ctx.availability_label ||
  "los próximos días";

const service =
  ctx.service_interest ||
  $json.service_interest ||
  "lavado_premium";

if (slots.length === 0) {
  const noSlotsMessage =
    `Por ahora no encontré horarios disponibles para ${availabilityLabel}. ` +
    `Si quieres, te puedo derivar para revisar manualmente una hora.`;

  return [{
    ...$json,
    message_to_send: noSlotsMessage,
    message: noSlotsMessage,
    db_operations: ["messages", "lead_state"],
    state_update: {
      ...($json.state_update || {}),
      stage: "booking_selection",
      intent_last: "availability_requested",
      next_goal: "manual_availability_review",
      last_bot_action: "no_available_slots_found",
      missing_fields: [],
      booking_options: [],
      availability_window: $json.availability_window || ctx.availability_window || "this_week",
      availability_label: availabilityLabel
    },
    notes: [
      ...($json.notes || []),
      "no_available_slots_found"
    ]
  }];
}

const lines = slots.map((slot, index) => {
  return `${index + 1}. ${formatSlot(slot)}`;
});

const optionNumbers =
  slots.length === 1
    ? "1"
    : slots.length === 2
      ? "1 o 2"
      : `${slots.slice(0, -1).map((_, index) => index + 1).join(", ")} o ${slots.length}`;

const wasSpecificSlotUnavailable =
  $json.unavailable_specific_slot === true ||
  $json.state_update?.intent_last === "manual_slot_unavailable";

const intro = wasSpecificSlotUnavailable
  ? `Ese horario no aparece disponible. Tengo estas opciones cercanas para ${serviceLabel(service)}:\n\n`
  : `Tengo estos horarios disponibles para ${serviceLabel(service)} durante ${availabilityLabel}:\n\n`;

const finalMessage =
  intro +
  `${lines.join("\n")}\n\n` +
  `¿Cuál te acomoda? Puedes responder con ${optionNumbers}.`;

