  if (!date || !time) return "ese horario";

  const start = new Date(`${date}T${time}:00`);

  if (isNaN(start.getTime())) {
    return `${date} a las ${time}`;
  }

  const fecha = start.toLocaleDateString("es-CL", {
    timeZone: "America/Santiago",
